public class CompileErrors {
    // ERROR 1: Type mismatch
    int x = 3.7;          // ERROR: cannot convert double to int

    // ERROR 2: Missing return
    int add(int a, int b) {
        int sum = a + b;  // ERROR: missing return statement
    }

    // ERROR 3: Using undeclared variable
    void printIt() {
        System.out.println(y);  // ERROR: cannot find symbol 'y'
    }

    // ERROR 4: Assignment in condition
    void check(int n) {
        if (n = 0) {           // ERROR: int cannot be converted to boolean
            System.out.println("zero");
        }
    }
}

public class RuntimeErrors {
    public static void main(String[] args) {

        // Runtime Error 1: ArithmeticException
        int a = 10, b = 0;
        System.out.println(a / b);   // Throws: ArithmeticException: / by zero
        // Note: a / 0.0 = Infinity (double division — no exception!)

        // Runtime Error 2: NullPointerException
        String s = null;
        System.out.println(s.length()); // Throws: NullPointerException

        // Runtime Error 3: ArrayIndexOutOfBounds
        int[] arr = new int[3];        // valid indices: 0, 1, 2
        System.out.println(arr[3]);    // Throws: ArrayIndexOutOfBoundsException: 3

        // Runtime Error 4: ClassCastException
        Object obj = Integer.valueOf(5);
        String str = (String) obj;     // Throws: ClassCastException
    }
}

// GOAL: Print 1 through 5
public class OffByOne {
    public static void main(String[] args) {
        // BUGGY version:
        for (int i = 1; i < 5; i++) {         // Bug: stops at 4!
            System.out.println(i);
        }
        // Output: 1 2 3 4  (missing 5)

        // FIXED version:
        for (int i = 1; i <= 5; i++) {        // Correct: includes 5
            System.out.println(i);
        }
        // Output: 1 2 3 4 5
    }
}

