    public static void main(String[] args) {
        int total = 95 + 87 + 73 + 88 + 92;
        int count = 5;
        double average = total / count;
        System.out.println("Average: " + average);
        // Expected: 87.0, Actual output: ???
    }
}

sections.fix:
public class E5 {
    public static void main(String[] args) {
        int total = 95 + 87 + 73 + 88 + 92;  // = 435
        int count = 5;
        double average = (double) total / count;  // Cast before division
        System.out.println("Average: " + average); // Average: 87.0
    }
}

